import { AppRouterLayout } from "@/components/layouts/app-router-layout";
import { env } from "@/env";
import { RenderBuilderContent } from "@/lib/builder-io/builder-io";
import { getPayloadClient } from "@/lib/payload/payload";
import type { Media, Page as PayloadPage } from "@/payload-types";
import "@/styles/builder-io.css";
import { type BuilderContent, builder } from "@builder.io/sdk";
import type { Metadata } from "next";
import { notFound } from "next/navigation";
import { Suspense } from "react";
import type { PageBlock } from "@/types/blocks";
import { BlockRenderer } from "../payload-blocks";

if (env.NEXT_PUBLIC_FEATURE_BUILDER_ENABLED && env.NEXT_PUBLIC_BUILDER_API_KEY) {
  builder.init(env.NEXT_PUBLIC_BUILDER_API_KEY);
}

interface PageProps {
  params: Promise<{
    slug: string[];
  }>;
  searchParams: Promise<{
    preview?: string;
  }>;
}

function Loading() {
  return <h2>🌀 Loading...</h2>;
}

const shouldSkip = (slugString: string) => {
  return (
    slugString.startsWith("api/") ||
    slugString.includes(".") || // Any file with extension
    slugString.includes(".well-known") || // Any file with extension
    // Next.js built-in routes
    slugString.includes("manifest.json") ||
    slugString.includes("sitemap.xml") ||
    slugString.includes("robots.txt") ||
    slugString.includes("favicon.ico") ||
    // Static assets
    slugString.startsWith("_next/") ||
    slugString.startsWith("static/") ||
    // Other common static files
    slugString.endsWith(".js") ||
    slugString.endsWith(".css") ||
    slugString.endsWith(".png") ||
    slugString.endsWith(".jpg") ||
    slugString.endsWith(".jpeg") ||
    slugString.endsWith(".gif") ||
    slugString.endsWith(".svg") ||
    slugString.endsWith(".ico") ||
    slugString.endsWith(".webp") ||
    slugString.endsWith(".woff") ||
    slugString.endsWith(".woff2") ||
    slugString.endsWith(".ttf") ||
    slugString.endsWith(".eot")
  );
};

async function getPageData(
  slug: string[],
  depth = 2
): Promise<
  { source: "payload"; data: PayloadPage } | { source: "builder"; data: BuilderContent } | null
> {
  if (!env.NEXT_PUBLIC_FEATURE_PAYLOAD_ENABLED && !env.NEXT_PUBLIC_FEATURE_BUILDER_ENABLED) {
    return notFound();
  }

  const slugString = slug.join("/");
  if (shouldSkip(slugString)) {
    return notFound();
  }

  if (env.NEXT_PUBLIC_FEATURE_PAYLOAD_ENABLED) {
    try {
      const payload = await getPayloadClient();

      // First try with the joined slug
      let pageQuery = await payload?.find({
        collection: "pages",
        where: { slug: { equals: slugString } },
        depth,
      });

      // If no results, try with just the first segment of the slug
      if (pageQuery?.docs?.length === 0 && slug.length > 0) {
        pageQuery = await payload?.find({
          collection: "pages",
          where: { slug: { equals: slug[0] } },
          depth,
        });
      }

      // Try a more flexible query if still not found
      if (pageQuery?.docs?.length === 0 && slug.length > 0) {
        pageQuery = await payload?.find({
          collection: "pages",
          where: { slug: { like: slug[0] } },
          depth,
        });
      }

      if (pageQuery?.docs[0]) {
        return { source: "payload", data: pageQuery.docs[0] };
      }
    } catch (error) {
      // Silently handle errors, as in original code
    }
  }

  if (env.NEXT_PUBLIC_FEATURE_BUILDER_ENABLED) {
    try {
      const slugString = slug.join("/");
      const builderContent = await builder
        .get("page", {
          userAttributes: {
            urlPath: `/${slugString}`,
          },
          prerender: false,
        })
        .toPromise();

      if (builderContent) {
        return { source: "builder", data: builderContent };
      }
    } catch (error) {
      // Silently handle errors
    }
  }

  return null;
}

export async function generateMetadata({
  params: paramsPromise,
  searchParams: searchParamsPromise,
}: PageProps): Promise<Metadata> {
  const params = await paramsPromise;
  // const searchParams = await searchParamsPromise;
  // const isPreview = searchParams.preview === "true";

  const pageData = await getPageData(params.slug, 1);
  if (!pageData) {
    return notFound();
  }

  if (pageData.source === "builder") {
    return {
      title: pageData.data.data?.title ?? "Page",
      description: pageData.data.data?.description ?? "",
    };
  }

  if (pageData.source === "payload") {
    const { meta } = pageData.data;
    const isMedia = (image: any): image is Media =>
      image && typeof image === "object" && "url" in image;

    return {
      title: meta?.title,
      description: meta?.description,
      openGraph:
        meta?.image && isMedia(meta.image) && meta.image.url
          ? {
              images: [
                {
                  url: meta.image.url,
                  width: 1200,
                  height: 630,
                },
              ],
            }
          : undefined,
    };
  }

  notFound();
}

export default async function Page({ params: paramsPromise }: PageProps) {
  const params = await paramsPromise;
  // const searchParams = await searchParamsPromise;
  // const isPreview = searchParams.preview === "true";

  const pageData = await getPageData(params.slug, 1);
  if (!pageData) {
    return notFound();
  }

  if (pageData.source === "payload" || pageData.source === "builder") {
    return (
      <Suspense fallback={<Loading />}>
        {pageData.source === "payload" && (
          <BlockRenderer blocks={(pageData.data.layout as PageBlock[]) ?? []} />
        )}

        {pageData.source === "builder" && (
          <RenderBuilderContent content={pageData.data} model="page" />
        )}
      </Suspense>
    );
  }

  notFound();
}

/**
 * Payload CMS route group layout.
 *
 * When Payload is disabled (no DATABASE_URL / PAYLOAD_SECRET), this layout
 * renders children directly — no @payloadcms packages are imported.
 *
 * When Payload is enabled, the heavy imports (CSS, RootLayout, config) are
 * loaded via a dynamic import of ./payload-root-layout so that Turbopack
 * can tree-shake them out of disabled builds and externalised packages
 * don't blow up on Vercel at runtime.
 */

import type React from "react";
import { env } from "@/env";

interface Args {
  children: React.ReactNode;
}

const Layout = async ({ children }: Args) => {
  if (!env.NEXT_PUBLIC_FEATURE_PAYLOAD_ENABLED) {
    return <>{children}</>;
  }

  const { default: PayloadRootLayout } = await import("./payload-root-layout");
  return <PayloadRootLayout>{children}</PayloadRootLayout>;
};

export default Layout;

/**
 * Isolated Payload root layout wrapper.
 *
 * All @payloadcms imports live here so they are only resolved when this
 * module is actually imported (i.e. when Payload is enabled).  The parent
 * layout.tsx conditionally `import()`s this file at runtime, keeping the
 * heavy / CSS-bearing Payload packages out of the bundle when the feature
 * flag is off.
 */

import config from "@payload-config";
import "@payloadcms/next/css";
import { handleServerFunctions, RootLayout } from "@payloadcms/next/layouts";
import type { ServerFunctionClient } from "payload";
import type React from "react";
import { importMap } from "./cms/importMap.js";

const serverFunction: ServerFunctionClient = async (args) => {
  "use server";
  return handleServerFunctions({
    ...args,
    config,
    importMap,
  });
};

export default function PayloadRootLayout({ children }: { children: React.ReactNode }) {
  return (
    <RootLayout config={config} importMap={importMap} serverFunction={serverFunction}>
      {children}
    </RootLayout>
  );
}

/* Not Found Page Component
 * This is a special Next.js page that renders when a route isn't found (404 error)
 * @see https://nextjs.org/docs/app/api-reference/file-conventions/not-found
 */

import { NotFoundPage } from "@/components/pages/not-found-page";

export default function NotFound() {
  return <NotFoundPage />;
}

import { v4 as uuidv4 } from "uuid";
import type {
  ContentBlock,
  FeaturesBlock,
  HeroBlock,
  PageBlock,
  TestimonialsBlock,
} from "@/types/blocks";
import { Content } from "./content";
import { Features } from "./features";
import { Hero } from "./hero";
import { Testimonials } from "./testimonials";

interface BlockRendererProps {
  blocks: PageBlock[];
  className?: string;
}

const renderBlock = (block: PageBlock) => {
  switch (block.blockType) {
    case "hero":
      return <Hero key={uuidv4()} block={block} />;
    case "content":
      return <Content key={uuidv4()} block={block} />;
    case "features":
      return <Features key={uuidv4()} block={block} />;
    case "testimonials":
      return <Testimonials key={uuidv4()} block={block} />;
    default:
      return null;
  }
};

export const BlockRenderer = ({ blocks, className }: BlockRendererProps) => {
  return <div className={className}>{blocks.map(renderBlock)}</div>;
};

export { Content } from "./content";
export { Features } from "./features";
export { Hero } from "./hero";
export { Testimonials } from "./testimonials";

import Image from "next/image";
import Link from "next/link";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import type { HeroBlock } from "@/types/blocks";

interface HeroProps {
  block: HeroBlock;
  className?: string;
}

export const Hero = ({ block, className }: HeroProps) => {
  const { heading, subheading, image, ctaText, ctaLink, style = "default" } = block;

  return (
    <section
      className={cn(
        "relative overflow-hidden py-20",
        {
          "text-center": style === "centered",
          "grid grid-cols-2 items-center gap-12": style === "split",
        },
        className
      )}
    >
      {/* Background image for default and centered styles */}
      {image?.url && (style === "default" || style === "centered") && (
        <div className="absolute inset-0 -z-10">
          <Image src={image.url} alt={heading} fill className="object-cover opacity-20" priority />
        </div>
      )}

      <div
        className={cn("container mx-auto px-4", {
          "max-w-4xl": style === "centered",
        })}
      >
        <div className="space-y-6">
          <h1 className="text-4xl font-bold tracking-tighter sm:text-5xl md:text-6xl">{heading}</h1>
          {subheading && <p className="text-xl text-muted-foreground">{subheading}</p>}
          {ctaText && ctaLink && (
            <div className="pt-4">
              <Button asChild size="lg">
                <Link href={ctaLink}>{ctaText}</Link>
              </Button>
            </div>
          )}
        </div>
      </div>

      {/* Side image for split layout */}
      {image?.url && style === "split" && (
        <div className="relative aspect-square w-full">
          <Image src={image.url} alt={heading} fill className="object-cover" priority />
        </div>
      )}
    </section>
  );
};

import { cn } from "@/lib/utils";
import type { ContentBlock } from "@/types/blocks";

interface ContentProps {
  block: ContentBlock;
  className?: string;
}

interface LexicalNode {
  type: string;
  tag?: string;
  children?: { text?: string }[];
}

function renderLexicalNode(node: LexicalNode, index: string) {
  switch (node.type) {
    case "paragraph":
      return (
        <p key={`p-${index}`} className="mb-4">
          {node.children?.[0]?.text || ""}
        </p>
      );
    case "heading":
      switch (node.tag) {
        case "h1":
          return (
            <h1 key={`h1-${index}`} className="mb-4 text-4xl font-bold">
              {node.children?.[0]?.text || ""}
            </h1>
          );
        case "h2":
          return (
            <h2 key={`h2-${index}`} className="mb-4 text-3xl font-bold">
              {node.children?.[0]?.text || ""}
            </h2>
          );
        case "h3":
          return (
            <h3 key={`h3-${index}`} className="mb-4 text-2xl font-bold">
              {node.children?.[0]?.text || ""}
            </h3>
          );
        default:
          return (
            <h4 key={`h4-${index}`} className="mb-4 text-xl font-bold">
              {node.children?.[0]?.text || ""}
            </h4>
          );
      }
    default:
      return null;
  }
}

export const Content = ({ block, className }: ContentProps) => {
  const { content, width = "default", background = "none" } = block;

  const nodes = content?.root?.children || [];

  return (
    <section
      className={cn(
        "py-16",
        {
          "bg-muted": background === "gray",
          "bg-primary/5": background === "accent",
        },
        className
      )}
    >
      <div
        className={cn("container mx-auto px-4", {
          "max-w-7xl": width === "wide",
          "max-w-3xl": width === "narrow",
          "max-w-5xl": width === "default",
        })}
      >
        <div className="prose prose-gray dark:prose-invert max-w-none">
          {nodes.map((node: LexicalNode, i: number) => renderLexicalNode(node, `node-${i}`))}
        </div>
      </div>
    </section>
  );
};

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  Carousel,
  CarouselContent,
  CarouselItem,
  CarouselNext,
  CarouselPrevious,
} from "@/components/ui/carousel";
import { cn } from "@/lib/utils";
import type { FeaturesBlock } from "@/types/blocks";

interface FeaturesProps {
  block: FeaturesBlock;
  className?: string;
}

export const Features = ({ block, className }: FeaturesProps) => {
  const { heading, features, layout = "grid", columns = "3" } = block;

  const renderFeature = (feature: any) => (
    <Card className="h-full">
      <CardHeader>
        {feature.icon && (
          <div className="mb-2 h-12 w-12 rounded-lg bg-primary/10 p-2.5">
            <feature.icon className="h-full w-full text-primary" />
          </div>
        )}
        <CardTitle>{feature.name}</CardTitle>
      </CardHeader>
      <CardContent>
        <p className="text-muted-foreground">{feature.description}</p>
      </CardContent>
    </Card>
  );

  return (
    <section className={cn("py-16", className)}>
      <div className="container mx-auto px-4">
        {heading && (
          <h2 className="mb-12 text-center text-3xl font-bold tracking-tighter sm:text-4xl">
            {heading}
          </h2>
        )}

        {layout === "grid" && (
          <div
            className={cn("grid gap-6", {
              "grid-cols-1 md:grid-cols-2": columns === "2",
              "grid-cols-1 md:grid-cols-3": columns === "3",
              "grid-cols-1 md:grid-cols-2 lg:grid-cols-4": columns === "4",
            })}
          >
            {features.map((feature) => (
              <div key={feature.id}>{renderFeature(feature)}</div>
            ))}
          </div>
        )}

        {layout === "list" && (
          <div className="space-y-6">
            {features.map((feature) => (
              <div key={feature.id} className="max-w-3xl mx-auto">
                {renderFeature(feature)}
              </div>
            ))}
          </div>
        )}

        {layout === "carousel" && (
          <Carousel className="w-full max-w-5xl mx-auto">
            <CarouselContent>
              {features.map((feature) => (
                <CarouselItem key={feature.id} className="md:basis-1/2 lg:basis-1/3">
                  {renderFeature(feature)}
                </CarouselItem>
              ))}
            </CarouselContent>
            <CarouselPrevious />
            <CarouselNext />
          </Carousel>
        )}
      </div>
    </section>
  );
};

import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Card, CardContent } from "@/components/ui/card";
import {
  Carousel,
  CarouselContent,
  CarouselItem,
  CarouselNext,
  CarouselPrevious,
} from "@/components/ui/carousel";
import { cn } from "@/lib/utils";
import type { TestimonialsBlock } from "@/types/blocks";

interface TestimonialsProps {
  block: TestimonialsBlock;
  className?: string;
}

export const Testimonials = ({ block, className }: TestimonialsProps) => {
  const { heading, testimonials, layout = "grid", background = "none" } = block;

  const renderTestimonial = (testimonial: any) => (
    <Card className="h-full">
      <CardContent className="pt-6">
        <div className="mb-4 flex items-center gap-4">
          <Avatar>
            {testimonial.image ? (
              <AvatarImage src={testimonial.image.url} alt={testimonial.name} />
            ) : (
              <AvatarFallback>{testimonial.name[0]}</AvatarFallback>
            )}
          </Avatar>
          <div>
            <div className="font-semibold">{testimonial.name}</div>
            {testimonial.title && (
              <div className="text-sm text-muted-foreground">{testimonial.title}</div>
            )}
          </div>
        </div>
        <blockquote className="text-muted-foreground">{testimonial.content}</blockquote>
      </CardContent>
    </Card>
  );

  return (
    <section
      className={cn(
        "py-16",
        {
          "bg-muted": background === "light",
          "bg-primary text-primary-foreground": background === "dark",
        },
        className
      )}
    >
      <div className="container mx-auto px-4">
        {heading && (
          <h2 className="mb-12 text-center text-3xl font-bold tracking-tighter sm:text-4xl">
            {heading}
          </h2>
        )}

        {layout === "grid" && (
          <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
            {testimonials.map((testimonial) => (
              <div key={testimonial.id}>{renderTestimonial(testimonial)}</div>
            ))}
          </div>
        )}

        {layout === "slider" && (
          <Carousel className="w-full max-w-5xl mx-auto">
            <CarouselContent>
              {testimonials.map((testimonial) => (
                <CarouselItem key={testimonial.id} className="md:basis-1/2">
                  {renderTestimonial(testimonial)}
                </CarouselItem>
              ))}
            </CarouselContent>
            <CarouselPrevious />
            <CarouselNext />
          </Carousel>
        )}

        {layout === "single" && (
          <div className="max-w-3xl mx-auto">
            {testimonials.slice(0, 1).map((testimonial) => (
              <div key={testimonial.id}>{renderTestimonial(testimonial)}</div>
            ))}
          </div>
        )}
      </div>
    </section>
  );
};

import type { Media } from "@/payload-types";

export interface HeroBlock {
  blockType: "hero";
  heading: string;
  subheading?: string;
  image?: Media;
  ctaText?: string;
  ctaLink?: string;
  style?: "default" | "centered" | "split";
}

export interface ContentBlock {
  blockType: "content";
  content: any; // Lexical editor content
  width?: "default" | "wide" | "narrow";
  background?: "none" | "gray" | "accent";
}

export interface FeaturesBlock {
  blockType: "features";
  heading?: string;
  features: {
    id: string;
    relationTo: "features";
  }[];
  layout?: "grid" | "list" | "carousel";
  columns?: "2" | "3" | "4";
}

export interface TestimonialsBlock {
  blockType: "testimonials";
  heading?: string;
  testimonials: {
    id: string;
    relationTo: "testimonials";
  }[];
  layout?: "grid" | "slider" | "single";
  background?: "none" | "light" | "dark";
}

export type PageBlock = HeroBlock | ContentBlock | FeaturesBlock | TestimonialsBlock;

export interface Page {
  id: string;
  title: string;
  slug: string;
  meta?: {
    title?: string;
    description?: string;
    image?: Media;
  };
  layout: PageBlock[];
  publishedAt?: string;
  createdAt: string;
  updatedAt: string;
}
